TabConfig = {}
TabConfig.Tabs = {}

function TabConfig:loadConfig()
    self:loadTabConfig()
end

function TabConfig:loadTabConfig()
    local configs = FileUtil.getConfigFromCsv("setting/Tabs.csv", 3)
    for _, config in pairs(configs) do
        local tab = {
            id = tonumber(config.id),
            icon = config.icon,
            name = config.name,
            isSelect = false
        }
        self.Tabs[tab.id] = tab
    end
end

function TabConfig:getTabs()
    return self.Tabs
end
